-- Luke Chapter 24
-- Theme: The Resurrection, the Emmaus Road, the Great Commission, and the Ascension
-- 53 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 24,
  'Luke 24 is the crowning chapter of the Third Gospel — the resolution of every prophetic promise, passion prediction, and theological thread woven through the preceding twenty-three chapters. The chapter opens at the empty tomb (vv.1-12), where the women who faithfully observed the burial (23:55) return at dawn on the first day of the week with prepared spices, only to find the stone rolled away and the body absent. Two angels (andres duo en esthēsi astraptousais — two men in dazzling garments, v.4) deliver the interpretive key to the entire Gospel: "He is not here, but is risen: remember how he spake unto you when he was yet in Galilee" (v.6). The resurrection is not an unexpected twist but the fulfillment of Jesus'' own repeated words (9:22; 18:33). The angels redirect the women from seeking "the living among the dead" (v.5) to remembering the prophetic word.' ||
  'The Emmaus road narrative (vv.13-35) is unique to Luke and is the longest post-resurrection appearance in any Gospel. Two disciples walk toward Emmaus, "and their eyes were holden that they should not know him" (v.16) — divine concealment that mirrors the disciples'' earlier incomprehension of the passion predictions (9:45; 18:34). Jesus walks alongside them incognito, conducting a comprehensive biblical theology lecture: "beginning at Moses and all the prophets, he expounded unto them in all the scriptures the things concerning himself" (v.27). The revelation comes not through sight but through Scripture and sacrament: "he was known of them in breaking of bread" (v.35). The Emmaus narrative teaches that the risen Christ is encountered in the interpreted Word and the shared bread — the ongoing pattern of Christian worship.' ||
  'The chapter''s climax is the appearance to the assembled disciples in Jerusalem (vv.36-49), where Jesus demonstrates his bodily resurrection (showing hands and feet, eating broiled fish), opens their minds to understand the Scriptures (v.45), and commissions them as witnesses to all nations, beginning from Jerusalem (vv.47-48). The promise of the Father — the Holy Spirit — is to be awaited in Jerusalem (v.49). The Gospel closes with the Ascension (vv.50-53), where Jesus blesses his disciples from Bethany and is "carried up into heaven" (v.51). The disciples return to Jerusalem "with great joy" (v.52) and are "continually in the temple, praising and blessing God" (v.53) — a conclusion that circles back to the temple where the Gospel began (1:5-23) and points forward to Acts, where the same temple becomes the first venue of apostolic witness.',
  'The Resurrection, the Emmaus Road, the Great Commission, and the Ascension',
  'ἀνίστημι (anistēmi)',
  'anistēmi means to raise up, to cause to stand, to resurrect — from ana (up) and histēmi (to stand, to set). The verb and its cognate noun anastasis (resurrection) dominate Luke 24 and indeed the theological climax of the entire Gospel. Jesus "is risen" (v.6, ēgerthē — was raised, passive voice: God raised him); the disciples report "The Lord is risen indeed" (v.34, ēgerthē ho Kurios ontōs). The passive voice (ēgerthē) rather than the active (anestē) is theologically significant: Jesus was raised by the Father''s power, affirming that the resurrection is the Father''s vindication of the Son''s obedience unto death. The word anistēmi echoes through Jesus'' three passion predictions (9:22; 18:33) and now finds its fulfillment. To "rise" means to stand up from death as one stands from sleep — embodied, conscious, and recognizable, yet transformed.',
  '["The Empty Tomb: He Is Not Here, But Is Risen (vv.1-12)","The Road to Emmaus: Christ Revealed in Word and Bread (vv.13-35)","Jesus Appears to the Disciples in Jerusalem (vv.36-43)","The Scriptures Opened and the Great Commission (vv.44-49)","The Ascension and the Disciples'' Joy (vv.50-53)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Now upon the first day of the week, very early in the morning, they came unto the sepulchre, bringing the spices which they had prepared, and certain others with them.', 'τῇ δὲ μιᾷ τῶν σαββάτων ὄρθρου βαθέως ἐπὶ τὸ μνῆμα ἦλθον φέρουσαι ἃ ἡτοίμασαν ἀρώματα.', 'tē de mia tōn sabbatōn orthrou batheōs epi to mnēma ēlthon pherousai ha hētoimasan arōmata.', '"The first day of the week" (tē mia tōn sabbatōn — on the first of the sabbaths, i.e., the first day of the week; the Jewish week was counted from the Sabbath, so the first day after Sabbath is Sunday) — this day will become the Christian Lord''s Day (Rev 1:10; Acts 20:7). "Very early in the morning" (orthrou batheōs — at deep dawn, the earliest possible moment; orthros = dawn; bathus = deep, profound; the expression suggests the transition from night to the first light). "Bringing the spices which they had prepared" (pherousai ha hētoimasan arōmata — carrying the spices they had prepared; cf. 23:56) — the women come expecting to anoint a dead body, not to witness a resurrection. Their devotion is expressed in practical service to what they believe is a corpse.', NULL),
  (2, 'And they found the stone rolled away from the sepulchre.', 'εὗρον δὲ τὸν λίθον ἀποκεκυλισμένον ἀπὸ τοῦ μνημείου,', 'heuron de ton lithon apokekylismenon apo tou mnēmeiou,', '"Found the stone rolled away" (heuron ton lithon apokekylismenon — they found the stone having been rolled away; apokuliō = to roll away; the perfect passive participle: it had been rolled away and remained in that state) — large disc-shaped stones were rolled along a groove to seal rock-hewn tombs, requiring considerable effort to move. The passive voice implies divine agency: the stone was not moved to let Jesus out (the risen Christ does not need stone removal to exit) but to let the witnesses in. The opened tomb is an invitation to see the evidence. Luke does not describe the moment of resurrection itself — no Gospel does — only its aftermath: an empty tomb and an opened stone.', NULL),
  (3, 'And they entered in, and found not the body of the Lord Jesus.', 'εἰσελθοῦσαι δὲ οὐχ εὗρον τὸ σῶμα τοῦ Κυρίου Ἰησοῦ.', 'eiselthousai de ouch heuron to sōma tou Kuriou Iēsou.', '"Entered in" (eiselthousai — having entered) — the women enter the tomb itself, an act of courage in the pre-dawn darkness. "Found not the body of the Lord Jesus" (ouch heuron to sōma tou Kuriou Iēsou — they did not find the body of the Lord Jesus) — Luke uses the full title "the Lord Jesus" (tou Kuriou Iēsou), a post-resurrection title expressing the church''s confession. The empty tomb is presented as a negative discovery: the body they came to anoint is simply not there. The absence of the body is the first datum; interpretation follows (vv.4-8). The empty tomb alone does not prove resurrection — it could theoretically be explained by theft or relocation — but combined with the angelic announcement and the resurrection appearances, it forms part of the cumulative evidence.', NULL),
  (4, 'And it came to pass, as they were much perplexed thereabout, behold, two men stood by them in shining garments:', 'καὶ ἐγένετο ἐν τῷ ἀπορεῖσθαι αὐτὰς περὶ τούτου, καὶ ἰδοὺ ἄνδρες δύο ἐπέστησαν αὐταῖς ἐν ἐσθῆτι ἀστραπτούσῃ.', 'kai egeneto en tō aporeisthai autas peri toutou, kai idou andres duo epestēsan autais en esthēti astraptousē.', '"Much perplexed" (aporeisthai — to be at a loss, to be utterly bewildered; aporeō from a-negative + poros/way = without a way, without an explanation) — the women have no framework for what they are experiencing. "Two men stood by them in shining garments" (andres duo epestēsan autais en esthēti astraptousē — two men stood beside them in garments that flashed like lightning; astraptō = to flash, to gleam like lightning; the same root as astrapē/lightning) — Luke describes them as "men" (andres) rather than "angels" (angeloi), though their supernatural nature is evident from their appearance. Two witnesses fulfills the Deuteronomic requirement for testimony (Deut 19:15). The same "two men in white apparel" will appear at the Ascension (Acts 1:10), creating a literary bracket around the resurrection-ascension narrative.', NULL),
  (5, 'And as they were afraid, and bowed down their faces to the earth, they said unto them, Why seek ye the living among the dead?', 'ἐμφόβων δὲ γενομένων αὐτῶν καὶ κλινουσῶν τὰ πρόσωπα εἰς τὴν γῆν, εἶπαν πρὸς αὐτάς, Τί ζητεῖτε τὸν ζῶντα μετὰ τῶν νεκρῶν;', 'emphobōn de genomenōn autōn kai klinousōn ta prosōpa eis tēn gēn, eipan pros autas, Ti zēteite ton zōnta meta tōn nekrōn?', '"Afraid, and bowed down their faces to the earth" (emphobōn genomenōn...kai klinousōn ta prosōpa eis tēn gēn — having become terrified...and bowing their faces to the ground; emphobos = in fear, terrified; a response to divine presence, cf. 1:12; 2:9) — the posture of prostration before a theophanic encounter. "Why seek ye the living among the dead?" (Ti zēteite ton zōnta meta tōn nekrōn — why do you seek the living one among the dead?) — one of the most profound questions in Scripture. "The living one" (ton zōnta — the living one; the present participle of zaō/to live; not merely "one who was alive" but "the Living One," echoing the divine title "the living God," cf. Josh 3:10; Dan 6:26; Rev 1:18: "I am he that liveth, and was dead"). The question reframes the entire situation: the tomb is a place of death; the one they seek is not dead but alive.', NULL),
  (6, 'He is not here, but is risen: remember how he spake unto you when he was yet in Galilee,', 'οὐκ ἔστιν ὧδε, ἀλλὰ ἠγέρθη· μνήσθητε ὡς ἐλάλησεν ὑμῖν ἔτι ὢν ἐν τῇ Γαλιλαίᾳ,', 'ouk estin hōde, alla ēgerthē; mnēsthēte hōs elalēsen humin eti ōn en tē Galilaia,', '"He is not here, but is risen" (ouk estin hōde, alla ēgerthē — he is not here, but has been raised; ēgerthē is the aorist passive: he was raised [by God], not "he rose" in the active voice) — the passive voice attributes the resurrection to the Father''s action. The announcement is stark and absolute: the tomb is empty because its occupant has been raised from the dead. "Remember how he spake unto you" (mnēsthēte hōs elalēsen humin — remember how he spoke to you) — the angels'' interpretive strategy is not to provide new revelation but to recall Jesus'' own words. The resurrection was predicted; the women need only remember. "When he was yet in Galilee" — the reference is to the passion predictions delivered during the Galilean ministry (9:22, 44; cf. 18:31-33).', NULL),
  (7, 'Saying, The Son of man must be delivered into the hands of sinful men, and be crucified, and the third day rise again.', 'λέγων, τὸν Υἱὸν τοῦ ἀνθρώπου ὅτι δεῖ παραδοθῆναι εἰς χεῖρας ἀνθρώπων ἁμαρτωλῶν καὶ σταυρωθῆναι καὶ τῇ τρίτῃ ἡμέρᾳ ἀναστῆναι.', 'legōn, ton Huion tou anthrōpou hoti dei paradothēnai eis cheiras anthrōpōn hamartōlōn kai staurōthēnai kai tē tritē hēmera anastēnai.', '"The Son of man must be delivered" (dei paradothēnai — it is divinely necessary to be handed over; dei = the word of divine necessity that pervades Luke''s passion narrative) — three infinitives summarize the entire Passion: (1) paradothēnai — to be handed over (into the hands of sinful men); (2) staurōthēnai — to be crucified; (3) anastēnai — to rise again. "Into the hands of sinful men" (eis cheiras anthrōpōn hamartōlōn — into the hands of sinful humans) — Luke replaces the specific agents (chief priests, scribes, Gentiles) with the general category "sinful men," universalizing the guilt. "The third day rise again" (tē tritē hēmera anastēnai — on the third day to rise up; anastēnai, the active infinitive of anistēmi = to stand up, to rise) — the resurrection was integral to the prediction, not appended as an afterthought. The angels interpret the empty tomb through Jesus'' own prophetic word.', NULL),
  (8, 'And they remembered his words,', 'καὶ ἐμνήσθησαν τῶν ῥημάτων αὐτοῦ,', 'kai emnēsthēsan tōn rhēmatōn autou,', '"They remembered his words" (emnēsthēsan tōn rhēmatōn autou — they recalled his words; mimnēskomai = to remember, to call to mind; rhēmatōn = words, utterances, specific sayings) — the remembering is the pivot point: the divine concealment that hid the passion predictions from the disciples'' understanding (9:45; 18:34) is now being lifted. What was "hid from them" is now recalled. The empty tomb, combined with the angelic reminder and the recalled prophetic words, produces the first glimmer of resurrection faith. Memory, Scripture, and eyewitness experience converge. This pattern will repeat throughout the chapter: Jesus opens minds to understand what they already knew but could not yet comprehend (vv.27, 32, 44-45).', NULL),
  (9, 'And returned from the sepulchre, and told all these things unto the eleven, and to all the rest.', 'καὶ ὑποστρέψασαι ἀπὸ τοῦ μνημείου ἀπήγγειλαν ταῦτα πάντα τοῖς ἕνδεκα καὶ πᾶσιν τοῖς λοιποῖς.', 'kai hupostrepsasai apo tou mnēmeiou apēngeilan tauta panta tois hendeka kai pasin tois loipois.', '"Returned from the sepulchre" (hupostrepsasai — having returned; hupostrephō is a Lucan favorite for purposeful return). "Told all these things unto the eleven" (apēngeilan tauta panta tois hendeka — they reported all these things to the Eleven; hendeka = eleven, the number reduced from twelve by Judas''s betrayal) — the women become the first witnesses and proclaimers of the resurrection, preceding even the apostles. "And to all the rest" (kai pasin tois loipois — and to all the remaining ones) — the wider circle of disciples beyond the Eleven also receives the testimony. The women fulfill the apostolic function of announcing the resurrection before the apostles do, a remarkable detail in a culture where women''s testimony was not accepted in court.', NULL),
  (10, 'It was Mary Magdalene, and Joanna, and Mary the mother of James, and other women that were with them, which told these things unto the apostles.', 'ἦσαν δὲ ἡ Μαγδαληνὴ Μαρία καὶ Ἰωάννα καὶ Μαρία ἡ Ἰακώβου καὶ αἱ λοιπαὶ σὺν αὐταῖς, ἔλεγον πρὸς τοὺς ἀποστόλους ταῦτα.', 'ēsan de hē Magdalēnē Maria kai Iōanna kai Maria hē Iakōbou kai hai loipai sun autais, elegon pros tous apostolous tauta.', '"Mary Magdalene" (hē Magdalēnē Maria — Mary the Magdalene, from Magdala on the western shore of Galilee; cf. 8:2, from whom seven demons were cast out). "Joanna" (Iōanna — wife of Chuza, Herod''s steward; cf. 8:3; unique to Luke, her presence connects the resurrection narrative to the Galilean ministry and to Herod''s own household). "Mary the mother of James" (Maria hē Iakōbou — Mary of James; probably James the Less/younger, Mark 15:40). "Other women that were with them" (hai loipai sun autais — the remaining women with them) — Luke names three and acknowledges more. "Told these things unto the apostles" (elegon pros tous apostolous — were telling the apostles; the imperfect elegon suggests repeated telling, as if they had to insist) — the first resurrection proclamation comes from women, a fact that strongly supports the historical authenticity of the accounts.', NULL),
  (11, 'And their words seemed to them as idle tales, and they believed them not.', 'καὶ ἐφάνησαν ἐνώπιον αὐτῶν ὡσεὶ λῆρος τὰ ῥήματα ταῦτα, καὶ ἠπίστουν αὐταῖς.', 'kai ephanēsan enōpion autōn hōsei lēros ta rhēmata tauta, kai ēpistoun autais.', '"Their words seemed to them as idle tales" (ephanēsan...hōsei lēros ta rhēmata — these words appeared to them as nonsense; lēros = silly talk, idle chatter, delirium, medical babbling; the word appears only here in the NT and was used in medical literature for the delirious speech of the fevered) — the apostles dismiss the women''s testimony as incoherent babbling. "They believed them not" (ēpistoun autais — they were disbelieving them; apisteō = to disbelieve, to refuse faith; the imperfect: they kept disbelieving) — the apostles'' initial response is stubborn incredulity. This detail is remarkably honest: the first witnesses were dismissed by the very community that would later proclaim the resurrection. The apostles'' unbelief undercuts any theory that the resurrection was a wish-fulfillment or collective hallucination — they were not predisposed to believe.', NULL),
  (12, 'Then arose Peter, and ran unto the sepulchre; and stooping down, he beheld the linen clothes laid by themselves, and departed, wondering in himself at that which was come to pass.', 'ὁ δὲ Πέτρος ἀναστὰς ἔδραμεν ἐπὶ τὸ μνημεῖον, καὶ παρακύψας βλέπει τὰ ὀθόνια μόνα, καὶ ἀπῆλθεν πρὸς ἑαυτὸν θαυμάζων τὸ γεγονός.', 'ho de Petros anastas edramen epi to mnēmeion, kai parakupsas blepei ta othonia mona, kai apēlthen pros heauton thaumazōn to gegonos.', '"Peter...ran unto the sepulchre" (Petros anastas edramen epi to mnēmeion — Peter having risen ran to the tomb; the urgency overrides the dismissiveness of v.11; despite the group''s unbelief, Peter investigates). "Stooping down" (parakupsas — having bent down to peer in; parakuptō = to bend beside/alongside, to stoop and look) — the tomb entrance was low, requiring bending to see inside. "He beheld the linen clothes laid by themselves" (blepei ta othonia mona — he sees the linen wrappings alone; othonia = linen strips/cloths used in burial; mona = alone, by themselves) — the graveclothes are present but the body is absent, a detail suggesting orderly departure rather than theft (a thief would take the body with wrappings). "Wondering in himself" (thaumazōn to gegonos — marveling at what had happened) — Peter is not yet at faith but at wonder, an intermediate state between disbelief and belief.', NULL),
  (13, 'And, behold, two of them went that same day to a village called Emmaus, which was from Jerusalem about threescore furlongs.', 'Καὶ ἰδοὺ δύο ἐξ αὐτῶν ἐν αὐτῇ τῇ ἡμέρᾳ ἦσαν πορευόμενοι εἰς κώμην ἀπέχουσαν σταδίους ἑξήκοντα ἀπὸ Ἰερουσαλήμ, ᾗ ὄνομα Ἐμμαούς,', 'Kai idou duo ex autōn en autē tē hēmera ēsan poreuomenoi eis kōmēn apechousan stadious hexēkonta apo Ierousalēm, hē onoma Emmaous,', '"Two of them" (duo ex autōn — two from among them; from the wider circle of disciples, not the Eleven, since the Emmaus pair will return to find "the eleven gathered together," v.33). "That same day" (en autē tē hēmera — on that very day, resurrection Sunday). "A village called Emmaus" (kōmēn...Emmaous — the exact location is debated; candidates include el-Qubeibeh, Abu Ghosh, Amwas/Nicopolis, and Motza; the identification remains uncertain). "Threescore furlongs" (stadious hexēkonta — sixty stadia, approximately seven miles; some manuscripts read 160 stadia, which would favor the Amwas identification) — a walkable distance for an afternoon journey. The Emmaus narrative is unique to Luke and is considered one of the masterpieces of NT storytelling, combining physical journey with theological discovery.', NULL),
  (14, 'And they talked together of all these things which had happened.', 'καὶ αὐτοὶ ὡμίλουν πρὸς ἀλλήλους περὶ πάντων τῶν συμβεβηκότων τούτων.', 'kai autoi hōmiloun pros allēlous peri pantōn tōn sumbebēkotōn toutōn.', '"Talked together" (hōmiloun pros allēlous — were conversing with one another; homileō = to be in company with, to converse, to discuss; the root of "homily") — the two disciples are processing the traumatic events through dialogue. "All these things which had happened" (pantōn tōn sumbebēkotōn toutōn — all these things that had happened together; sumbainō = to come together, to happen, to occur; the perfect tense: events that have happened and whose impact continues) — the conversation encompasses the crucifixion, burial, and the morning''s bewildering report from the women. They are walking away from Jerusalem, the city of salvation events, carrying unresolved grief and confusion. The movement away from Jerusalem is a physical metaphor for their spiritual state: moving away from the locus of God''s action.', NULL),
  (15, 'And it came to pass, that, while they communed together and reasoned, Jesus himself drew near, and went with them.', 'καὶ ἐγένετο ἐν τῷ ὁμιλεῖν αὐτοὺς καὶ συζητεῖν, καὶ αὐτὸς Ἰησοῦς ἐγγίσας συνεπορεύετο αὐτοῖς·', 'kai egeneto en tō homilein autous kai suzētein, kai autos Iēsous engisas suneporeuto autois;', '"While they communed together and reasoned" (en tō homilein autous kai suzētein — while they were conversing and debating; suzēteō = to seek together, to debate, to argue back and forth) — the questioning and disputing indicate intellectual and spiritual struggle. "Jesus himself drew near" (autos Iēsous engisas — Jesus himself having drawn near; the emphatic autos stresses that it is Jesus himself, not a vision or spirit) "and went with them" (suneporeuto autois — was traveling with them; the imperfect: he was walking alongside them, keeping pace, joining their journey) — the risen Christ enters the narrative by joining two obscure disciples on an ordinary road. The pattern is characteristic: Christ comes alongside those in grief and confusion, walking with them before revealing himself.', NULL),
  (16, 'But their eyes were holden that they should not know him.', 'οἱ δὲ ὀφθαλμοὶ αὐτῶν ἐκρατοῦντο τοῦ μὴ ἐπιγνῶναι αὐτόν.', 'hoi de ophthalmoi autōn ekratounto tou mē epignōnai auton.', '"Their eyes were holden" (hoi ophthalmoi autōn ekratounto — their eyes were being held, were being restrained; krateō = to hold, to grasp firmly; the passive: their eyes were held by an outside power) "that they should not know him" (tou mē epignōnai auton — so as not to recognize him; epiginōskō = to know fully, to recognize) — divine agency prevents recognition. This is not a failure of Jesus'' appearance but a deliberate act of concealment. The concealment serves the narrative''s pedagogical purpose: the disciples must first hear the Scriptures explained (v.27) before they see the risen Christ. Revelation follows interpretation; sight follows understanding. The concealment also mirrors the earlier veiling of understanding during the passion predictions (9:45; 18:34): what God concealed in the passion he now conceals temporarily in the resurrection.', NULL),
  (17, 'And he said unto them, What manner of communications are these that ye have one to another, as ye walk, and are sad?', 'εἶπεν δὲ πρὸς αὐτούς, Τίνες οἱ λόγοι οὗτοι οὓς ἀντιβάλλετε πρὸς ἀλλήλους περιπατοῦντες; καὶ ἐστάθησαν σκυθρωποί.', 'eipen de pros autous, Tines hoi logoi houtoi hous antiballete pros allēlous peripatountes? kai estathēsan skuthrōpoi.', '"What manner of communications are these" (Tines hoi logoi houtoi hous antiballete — what words are these that you are exchanging; antiballō = to throw back and forth, to exchange; the word suggests animated, back-and-forth discussion). "As ye walk, and are sad" (peripatountes...estathēsan skuthrōpoi — walking...they stood with gloomy faces; skuthrōpos = sullen-faced, downcast, gloomy; from skuthros/angry + ōps/face; the word appears only here and Matt 6:16 in the NT) — they literally stop in their tracks, their faces reflecting their grief. The question is pastorally brilliant: Jesus engages them where they are — in their confusion and sorrow — rather than immediately revealing himself. He draws out their grief before addressing it.', NULL),
  (18, 'And the one of them, whose name was Cleopas, answering said unto him, Art thou only a stranger in Jerusalem, and hast not known the things which are come to pass there in these days?', 'ἀποκριθεὶς δὲ εἷς ὀνόματι Κλεοπᾶς εἶπεν πρὸς αὐτόν, Σὺ μόνος παροικεῖς Ἰερουσαλὴμ καὶ οὐκ ἔγνως τὰ γενόμενα ἐν αὐτῇ ἐν ταῖς ἡμέραις ταύταις;', 'apokritheis de heis onomati Kleopas eipen pros auton, Su monos paroikeis Ierousalēm kai ouk egnōs ta genomena en autē en tais hēmerais tautais?', '"Cleopas" (Kleopas — possibly a contraction of Kleopatros; some identify him with Clopas of John 19:25, though they are different Greek names. His unnamed companion has been variously identified as his wife, Luke himself, or another disciple). "Art thou only a stranger in Jerusalem" (Su monos paroikeis Ierousalēm — Are you the only stranger/sojourner in Jerusalem; paroikeō = to dwell beside, to live as a foreigner, to sojourn; the irony is breathtaking: the one who is questioned as a stranger is the one to whom Jerusalem most centrally belongs). "Hast not known the things which are come to pass" (ouk egnōs ta genomena — you have not known the events that happened) — Cleopas assumes that everyone in Jerusalem knows about the crucifixion. The dramatic irony is that the "stranger" knows these events more intimately than anyone alive.', NULL),
  (19, 'And he said unto them, What things? And they said unto him, Concerning Jesus of Nazareth, which was a prophet mighty in deed and word before God and all the people:', 'καὶ εἶπεν αὐτοῖς, Ποῖα; οἱ δὲ εἶπαν αὐτῷ, Τὰ περὶ Ἰησοῦ τοῦ Ναζαρηνοῦ, ὃς ἐγένετο ἀνὴρ προφήτης δυνατὸς ἐν ἔργῳ καὶ λόγῳ ἐναντίον τοῦ Θεοῦ καὶ παντὸς τοῦ λαοῦ·', 'kai eipen autois, Poia? hoi de eipan autō, Ta peri Iēsou tou Nazarēnou, hos egeneto anēr prophētēs dunatos en ergō kai logō enantion tou Theou kai pantos tou laou;', '"What things?" (Poia — what kind of things? which things?) — Jesus invites them to articulate their understanding, a Socratic method of drawing out what they already know before correcting and completing it. "Concerning Jesus of Nazareth" (Ta peri Iēsou tou Nazarēnou — the things about Jesus the Nazarene) — they begin their Christological summary. "A prophet mighty in deed and word" (anēr prophētēs dunatos en ergō kai logō — a man, a prophet, powerful in deed and word) — their Christology is true but incomplete: they recognize Jesus as a prophet (cf. 7:16; 9:19) but not yet as the risen Messiah. "Before God and all the people" (enantion tou Theou kai pantos tou laou — in the presence of God and all the people) — his authority was demonstrated in both the divine and human spheres. The description echoes Moses (Acts 7:22; Deut 34:10-12), the prophet par excellence.', NULL),
  (20, 'And how the chief priests and our rulers delivered him to be condemned to death, and have crucified him.', 'ὅπως τε παρέδωκαν αὐτὸν οἱ ἀρχιερεῖς καὶ οἱ ἄρχοντες ἡμῶν εἰς κρίμα θανάτου καὶ ἐσταύρωσαν αὐτόν.', 'hopōs te paredōkan auton hoi archiereis kai hoi archontes hēmōn eis krima thanatou kai estaurōsan auton.', '"The chief priests and our rulers" (hoi archiereis kai hoi archontes hēmōn — the chief priests and our rulers) — the responsibility is placed on the Jewish leadership. "Delivered him to be condemned to death" (paredōkan auton eis krima thanatou — they handed him over to a death sentence; paradidōmi again, the handing-over language). "Have crucified him" (estaurōsan auton — they crucified him) — the summary is factual and compressed. The disciples'' narrative is a mini-passion account told from the perspective of grief and bewilderment. Their understanding extends to the crucifixion but not beyond it; the cross, for them, is the end of the story rather than its climax. This is the interpretive gap that Jesus will fill in vv.25-27.', NULL),
  (21, 'But we trusted that it had been he which should have redeemed Israel: and beside all this, to day is the third day since these things were done.', 'ἡμεῖς δὲ ἠλπίζομεν ὅτι αὐτός ἐστιν ὁ μέλλων λυτροῦσθαι τὸν Ἰσραήλ· ἀλλά γε καὶ σὺν πᾶσιν τούτοις τρίτην ταύτην ἡμέραν ἄγει ἀφ'' οὗ ταῦτα ἐγένετο.', 'hēmeis de ēlpizomen hoti autos estin ho mellōn lutrousthai ton Israēl; alla ge kai sun pasin toutois tritēn tautēn hēmeran agei aph'' hou tauta egeneto.', '"We trusted" (ēlpizomen — we were hoping; the imperfect tense is devastating: "we used to hope," "we had been hoping" — past tense hope, now abandoned) — the verb captures the death of messianic expectation. "He which should have redeemed Israel" (ho mellōn lutrousthai ton Israēl — the one about to redeem Israel; lutroō = to ransom, to liberate, to redeem; the word of Exodus liberation, cf. 1:68; 2:38) — their hope was for national-political redemption. "To day is the third day" (tritēn tautēn hēmeran agei — it is leading/spending this third day) — they note the third day but cannot connect it to Jesus'' own prediction that he would rise on the third day (9:22; 18:33). The very fact that corroborates the resurrection prediction is mentioned as a marker of finality: three days have passed, and their hope has died.', NULL),
  (22, 'Yea, and certain women also of our company made us astonished, which were early at the sepulchre;', 'ἀλλὰ καὶ γυναῖκές τινες ἐξ ἡμῶν ἐξέστησαν ἡμᾶς, γενόμεναι ὀρθριναὶ ἐπὶ τὸ μνημεῖον,', 'alla kai gunaikes tines ex hēmōn exestēsan hēmas, genomenai orthrinai epi to mnēmeion,', '"Certain women also of our company made us astonished" (gunaikes tines ex hēmōn exestēsan hēmas — some women from our group astonished us; existēmi = to displace, to astonish, to put out of one''s senses; the word suggests bewilderment rather than belief). "Which were early at the sepulchre" (genomenai orthrinai epi to mnēmeion — having been early at the tomb; orthrinos = early morning, at dawn) — Cleopas reports the women''s testimony but with a tone of amazement rather than faith. The women''s report is part of the data they cannot process: it astonishes but does not convince. This honest reporting of the disciples'' failure to believe the women further strengthens the historicity of the account.', NULL),
  (23, 'And when they found not his body, they came, saying, that they had also seen a vision of angels, which said that he was alive.', 'καὶ μὴ εὑροῦσαι τὸ σῶμα αὐτοῦ ἦλθον λέγουσαι καὶ ὀπτασίαν ἀγγέλων ἑωρακέναι, οἳ λέγουσιν αὐτὸν ζῆν.', 'kai mē heurousai to sōma autou ēlthon legousai kai optasian angelōn heōrakenai, hoi legousin auton zēn.', '"Found not his body" (mē heurousai to sōma autou — not having found his body) — the empty tomb is confirmed again. "A vision of angels, which said that he was alive" (optasian angelōn heōrakenai, hoi legousin auton zēn — to have seen a vision of angels who say he is alive; optasia = a vision, an apparition) — Cleopas categorizes the angelic appearance as an "optasia" (vision), which subtly downgrades it from objective reality to subjective experience. "Said that he was alive" (legousin auton zēn — say that he lives) — the core message (he lives!) reaches Cleopas but cannot penetrate his interpretive framework. He has the data — empty tomb, angelic announcement, a report of life — but lacks the hermeneutical key to assemble it into resurrection faith. That key is what Jesus is about to provide.', NULL),
  (24, 'And certain of them which were with us went to the sepulchre, and found it even so as the women had said: but him they saw not.', 'καὶ ἀπῆλθόν τινες τῶν σὺν ἡμῖν ἐπὶ τὸ μνημεῖον, καὶ εὗρον οὕτως καθὼς καὶ αἱ γυναῖκες εἶπον· αὐτὸν δὲ οὐκ εἶδον.', 'kai apēlthon tines tōn sun hēmin epi to mnēmeion, kai heuron houtōs kathōs kai hai gunaikes eipon; auton de ouk eidon.', '"Certain of them which were with us went to the sepulchre" (apēlthon tines tōn sun hēmin — some of those with us went to the tomb) — a reference to Peter (v.12) and possibly John (cf. John 20:3-8). "Found it even so as the women had said" (heuron houtōs kathōs kai hai gunaikes eipon — they found it just as the women also said) — the women''s testimony is independently confirmed: the tomb is empty, the body absent, the graveclothes present. "But him they saw not" (auton de ouk eidon — but him they did not see) — the concluding phrase contains the crux of their despair: the tomb is empty, but the risen Lord has not been seen. They have evidence of absence but not yet evidence of presence. The empty tomb alone is necessary but insufficient; the resurrection appearances are needed to complete the picture.', NULL),
  (25, 'Then he said unto them, O fools, and slow of heart to believe all that the prophets have spoken:', 'καὶ αὐτὸς εἶπεν πρὸς αὐτούς, Ὦ ἀνόητοι καὶ βραδεῖς τῇ καρδίᾳ τοῦ πιστεύειν ἐπὶ πᾶσιν οἷς ἐλάλησαν οἱ προφῆται·', 'kai autos eipen pros autous, Ō anoētoi kai bradeis tē kardia tou pisteuein epi pasin hois elalēsan hoi prophētai;', '"O fools" (Ō anoētoi — O foolish ones, O senseless ones; anoētos from a-negative + noeō/to think = without understanding, not having used the mind; Gal 3:1 uses the same word) — the address is not harsh contempt but affectionate rebuke. "Slow of heart to believe" (bradeis tē kardia tou pisteuein — slow in heart to believe; bradus = slow, sluggish; the problem is not intellectual incapacity but a resistant heart that is slow to trust) — their hearts, not their minds, are the obstacle. "All that the prophets have spoken" (epi pasin hois elalēsan hoi prophētai — in all things which the prophets spoke) — the word "all" (pasin) is emphatic: they believe selectively, accepting the prophecies of messianic triumph but rejecting those of messianic suffering. Their error is not disbelief in Scripture but a partial, selective reading that excludes the suffering servant tradition.', NULL),
  (26, 'Ought not Christ to have suffered these things, and to enter into his glory?', 'οὐχὶ ταῦτα ἔδει παθεῖν τὸν Χριστὸν καὶ εἰσελθεῖν εἰς τὴν δόξαν αὐτοῦ;', 'ouchi tauta edei pathein ton Christon kai eiselthein eis tēn doxan autou?', '"Ought not Christ to have suffered these things" (ouchi tauta edei pathein ton Christon — was it not necessary for the Christ to suffer these things; edei = it was divinely necessary, the word of divine dei that governs the entire passion narrative) — the question expects an affirmative answer: yes, it was necessary. The cross is not a detour from God''s plan but its central highway. "And to enter into his glory" (kai eiselthein eis tēn doxan autou — and to enter into his glory; doxa = glory, the divine radiance and honor) — suffering precedes glory; the cross precedes the crown. This is the hermeneutical principle that unlocks the entire OT: the Messiah''s path runs through suffering to glory, through death to resurrection. The disciples'' error was assuming glory without suffering; the corrected understanding sees suffering as the necessary pathway to glory.', NULL),
  (27, 'And beginning at Moses and all the prophets, he expounded unto them in all the scriptures the things concerning himself.', 'καὶ ἀρξάμενος ἀπὸ Μωϋσέως καὶ ἀπὸ πάντων τῶν προφητῶν διερμήνευσεν αὐτοῖς ἐν πάσαις ταῖς γραφαῖς τὰ περὶ ἑαυτοῦ.', 'kai arxamenos apo Mōuseōs kai apo pantōn tōn prophētōn diermēneusen autois en pasais tais graphais ta peri heautou.', '"Beginning at Moses and all the prophets" (arxamenos apo Mōuseōs kai apo pantōn tōn prophētōn — beginning from Moses and from all the prophets) — the entire OT canon is surveyed: the Pentateuch (Moses) and the Prophets (covering the Former and Latter Prophets, and by extension the Writings). "He expounded unto them" (diermēneusen autois — he interpreted for them; diermēneuō = to translate, to interpret, to explain thoroughly; dia = through + hermēneuō = to interpret, the root of "hermeneutics") — Jesus conducts a comprehensive hermeneutical tour of the OT. "In all the scriptures the things concerning himself" (en pasais tais graphais ta peri heautou — in all the Scriptures the things about himself) — the Christological reading of the OT: the entire Hebrew Bible, rightly read, speaks of Christ. This verse is the foundation of Christian biblical interpretation.', NULL),
  (28, 'And they drew nigh unto the village, whither they went: and he made as though he would have gone further.', 'Καὶ ἤγγισαν εἰς τὴν κώμην οὗ ἐπορεύοντο, καὶ αὐτὸς προσεποιήσατο πορρώτερον πορεύεσθαι.', 'Kai ēngisan eis tēn kōmēn hou eporeuonto, kai autos prosepoiēsato porrōteron poreuesthai.', '"They drew nigh unto the village" (ēngisan eis tēn kōmēn — they drew near to the village) — the seven-mile journey is nearly complete. "He made as though he would have gone further" (prosepoiēsato porrōteron poreuesthai — he made as if to travel further; prospoieomai = to pretend, to act as if, to make a show of) — Jesus does not force his presence upon them; he gives them the opportunity to invite or to let him pass. The risen Christ respects human freedom; he does not compel but waits to be welcomed. The gesture creates the occasion for hospitality — the same hospitality through which he will be revealed (v.35). The pattern is Johannine as well: "Behold, I stand at the door, and knock" (Rev 3:20).', NULL),
  (29, 'But they constrained him, saying, Abide with us: for it is toward evening, and the day is far spent. And he went in to tarry with them.', 'καὶ παρεβιάσαντο αὐτὸν λέγοντες, Μεῖνον μεθ'' ἡμῶν, ὅτι πρὸς ἑσπέραν ἐστὶν καὶ κέκλικεν ἤδη ἡ ἡμέρα. καὶ εἰσῆλθεν τοῦ μεῖναι σὺν αὐτοῖς.', 'kai parebiasanto auton legontes, Meinon meth'' hēmōn, hoti pros hesperan estin kai kekliken ēdē hē hēmera. kai eisēlthen tou meinai sun autois.', '"They constrained him" (parebiasanto auton — they urged him strongly, they pressed him; parabiazomai = to force beside, to compel by entreaty; the word indicates persistent, earnest invitation, not physical coercion, cf. Acts 16:15). "Abide with us" (Meinon meth'' hēmōn — stay with us; menō = to remain, to abide; the imperative of invitation) — the simplest and most consequential request in the narrative. "It is toward evening, and the day is far spent" (pros hesperan estin kai kekliken ēdē hē hēmera — it is toward evening and the day has already declined) — the practical reason for hospitality conceals a deeper truth: they are in spiritual twilight, and the light they need is about to dawn. "He went in to tarry with them" (eisēlthen tou meinai sun autois — he entered to stay with them) — the guest becomes the host in v.30.', NULL),
  (30, 'And it came to pass, as he sat at meat with them, he took bread, and blessed it, and brake, and gave to them.', 'καὶ ἐγένετο ἐν τῷ κατακλιθῆναι αὐτὸν μετ'' αὐτῶν λαβὼν τὸν ἄρτον εὐλόγησεν καὶ κλάσας ἐπεδίδου αὐτοῖς.', 'kai egeneto en tō kataklithēnai auton met'' autōn labōn ton arton eulogēsen kai klasas epedidou autois.', '"As he sat at meat with them" (en tō kataklithēnai auton met'' autōn — when he reclined at table with them; kataklinomai = to recline, the dining posture). "He took bread, and blessed it, and brake, and gave to them" (labōn ton arton eulogēsen kai klasas epedidou autois — having taken the bread, he blessed and having broken was giving to them) — the four verbs (took, blessed, broke, gave) precisely echo the Last Supper (22:19) and the feeding of the five thousand (9:16). The guest has assumed the role of host: the stranger they invited to dinner is now presiding at table, performing the head-of-household action of blessing and distributing bread. The recognition will come through this sacramental action — Christ revealed in the breaking of bread. The imperfect epedidou (was giving) suggests the action was ongoing when recognition occurred.', NULL),
  (31, 'And their eyes were opened, and they knew him; and he vanished out of their sight.', 'αὐτῶν δὲ διηνοίχθησαν οἱ ὀφθαλμοί, καὶ ἐπέγνωσαν αὐτόν· καὶ αὐτὸς ἄφαντος ἐγένετο ἀπ'' αὐτῶν.', 'autōn de diēnoichthēsan hoi ophthalmoi, kai epegnōsan auton; kai autos aphantos egeneto ap'' autōn.', '"Their eyes were opened" (diēnoichthēsan hoi ophthalmoi — their eyes were opened wide; dianoigō = to open thoroughly, to open completely; dia = through + anoigō = to open; the divine passive: God opened their eyes, reversing the concealment of v.16). "They knew him" (epegnōsan auton — they recognized him fully; epiginōskō = to know upon, to recognize clearly; the full recognition that was blocked in v.16 now floods in). "He vanished out of their sight" (autos aphantos egeneto ap'' autōn — he became invisible from them; aphantos = invisible, unseen, disappeared; from a-negative + phainō/to appear) — the moment of recognition coincides with his disappearance. Christ is recognized in the breaking of bread and then becomes invisible — establishing the pattern of Christian experience: his presence is known through Word and sacrament, not continuous physical visibility.', NULL),
  (32, 'And they said one to another, Did not our heart burn within us, while he talked with us by the way, and while he opened to us the scriptures?', 'καὶ εἶπαν πρὸς ἀλλήλους, Οὐχὶ ἡ καρδία ἡμῶν καιομένη ἦν ἐν ἡμῖν ὡς ἐλάλει ἡμῖν ἐν τῇ ὁδῷ, ὡς διήνοιγεν ἡμῖν τὰς γραφάς;', 'kai eipan pros allēlous, Ouchi hē kardia hēmōn kaiomenē ēn en hēmin hōs elalei hēmin en tē hodō, hōs diēnoigen hēmin tas graphas?', '"Did not our heart burn within us" (Ouchi hē kardia hēmōn kaiomenē ēn — was not our heart burning; kaiō = to burn, to set on fire; the periphrastic imperfect: was continuously burning) — the burning heart is the retroactive recognition of Christ''s presence. They now realize that the experience of the Scripture exposition was itself an encounter with the risen Lord, even before they recognized him visually. "While he talked with us by the way" (hōs elalei hēmin en tē hodō — while he was speaking to us on the road). "While he opened to us the scriptures" (hōs diēnoigen hēmin tas graphas — while he was opening for us the Scriptures; dianoigō again, the same word used for their eyes being opened in v.31) — Scripture-opening and eye-opening are parallel acts of the same Christ. The burning heart is the subjective experience of the Spirit''s illumination through the Word.', NULL),
  (33, 'And they rose up the same hour, and returned to Jerusalem, and found the eleven gathered together, and them that were with them,', 'καὶ ἀναστάντες αὐτῇ τῇ ὥρᾳ ὑπέστρεψαν εἰς Ἰερουσαλήμ, καὶ εὗρον ἠθροισμένους τοὺς ἕνδεκα καὶ τοὺς σὺν αὐτοῖς,', 'kai anastantes autē tē hōra hupestrepsan eis Ierousalēm, kai heuron ēthroismenous tous hendeka kai tous sun autois,', '"Rose up the same hour" (anastantes autē tē hōra — having risen that very hour; despite the evening hour, v.29, they immediately reverse their journey) — the urgency of resurrection news overrides every practical consideration. The seven-mile return to Jerusalem in the dark demonstrates the transformative power of the encounter. "Returned to Jerusalem" (hupestrepsan eis Ierousalēm — they returned to Jerusalem) — the movement reverses: they had been walking away from Jerusalem in despair; now they rush back in joy. "Found the eleven gathered together" (heuron ēthroismenous tous hendeka — they found the Eleven assembled; athroizō = to gather, to assemble) — the community is regathering, drawn together by the resurrection reports.', NULL),
  (34, 'Saying, The Lord is risen indeed, and hath appeared to Simon.', 'λέγοντας ὅτι ὄντως ἠγέρθη ὁ Κύριος καὶ ὤφθη Σίμωνι.', 'legontas hoti ontōs ēgerthē ho Kurios kai ōphthē Simōni.', '"The Lord is risen indeed" (ontōs ēgerthē ho Kurios — truly the Lord has been raised; ontōs = really, in truth, certainly; ēgerthē = was raised, the divine passive) — this confession is already on the lips of the eleven when the Emmaus pair arrives. The community has moved from the "idle tales" of v.11 to the confession "risen indeed." "Hath appeared to Simon" (ōphthē Simōni — he appeared to Simon; ōphthē = was seen, appeared; the theological passive: he allowed himself to be seen by Simon/Peter) — this appearance to Peter is not narrated by Luke but is confirmed by Paul (1 Cor 15:5: "he was seen of Cephas") and is the earliest resurrection appearance to an individual apostle. The appearance to Peter is theologically significant: the one who denied Christ three times is the first apostle to whom the risen Christ appears, confirming the restoration promised in 22:32.', NULL),
  (35, 'And they told what things were done in the way, and how he was known of them in breaking of bread.', 'καὶ αὐτοὶ ἐξηγοῦντο τὰ ἐν τῇ ὁδῷ καὶ ὡς ἐγνώσθη αὐτοῖς ἐν τῇ κλάσει τοῦ ἄρτου.', 'kai autoi exēgounto ta en tē hodō kai hōs egnōsthē autois en tē klasei tou artou.', '"They told what things were done in the way" (exēgounto ta en tē hodō — they were narrating the things on the road; exēgeomai = to lead out, to narrate, to explain; the root of "exegesis") — the Emmaus pair now becomes witnesses, adding their testimony to the community''s growing body of evidence. "How he was known of them in breaking of bread" (hōs egnōsthē autois en tē klasei tou artou — how he was recognized by them in the breaking of the bread; hē klasis tou artou = the breaking of the bread, a phrase that becomes the early church''s term for the Eucharist, cf. Acts 2:42, 46; 20:7) — the mode of recognition is sacramental: not through spectacular signs but through the ordinary act of breaking bread together. This establishes the theological pattern: the risen Christ is encountered in the community''s worship, in the proclaimed Word (v.32) and the broken bread (v.35).', NULL),
  (36, 'And as they thus spake, Jesus himself stood in the midst of them, and saith unto them, Peace be unto you.', 'Ταῦτα δὲ αὐτῶν λαλούντων αὐτὸς ἔστη ἐν μέσῳ αὐτῶν καὶ λέγει αὐτοῖς, Εἰρήνη ὑμῖν.', 'Tauta de autōn lalountōn autos estē en mesō autōn kai legei autois, Eirēnē humin.', '"As they thus spake" (Tauta autōn lalountōn — while they were saying these things; the genitive absolute indicates a sudden interruption) — Jesus appears while the community is in the act of bearing witness to him. "Jesus himself stood in the midst of them" (autos estē en mesō autōn — he himself stood in the middle of them; the emphatic autos stresses the real, personal presence; estē = stood, the aorist suggesting sudden appearance) — the appearance is abrupt and unannounced, without entering through a door (cf. John 20:19: "the doors being shut"). "Peace be unto you" (Eirēnē humin — peace to you; the standard Jewish greeting, shalom aleichem, but now freighted with resurrection significance) — the peace Jesus gives is not mere social convention but the eschatological peace promised in Isaiah 9:6-7, the fruit of his completed work on the cross.', NULL),
  (37, 'But they were terrified and affrighted, and supposed that they had seen a spirit.', 'πτοηθέντες δὲ καὶ ἔμφοβοι γενόμενοι ἐδόκουν πνεῦμα θεωρεῖν.', 'ptoēthentes de kai emphoboi genomenoi edokoun pneuma theōrein.', '"Terrified and affrighted" (ptoēthentes kai emphoboi genomenoi — having been startled and having become fearful; ptoeō = to startle, to terrify, cf. 21:9; emphobos = in fear, full of fear) — the disciples'' initial response to the resurrection appearance is fear, not joy. "Supposed that they had seen a spirit" (edokoun pneuma theōrein — they were thinking they were seeing a ghost; pneuma here = ghost, disembodied spirit, an apparition) — their first interpretation is that Jesus is a phantasm, a disembodied spirit. This assumption is theologically significant: it reveals that the disciples'' default understanding did not include bodily resurrection. They had to be convinced against their initial interpretation, which strengthens the case for the historical reality of the appearances.', NULL),
  (38, 'And he said unto them, Why are ye troubled? and why do thoughts arise in your hearts?', 'καὶ εἶπεν αὐτοῖς, Τί τεταραγμένοι ἐστέ, καὶ διὰ τί διαλογισμοὶ ἀναβαίνουσιν ἐν τῇ καρδίᾳ ὑμῶν;', 'kai eipen autois, Ti tetaragmenoi este, kai dia ti dialogismoi anabainousin en tē kardia humōn?', '"Why are ye troubled?" (Ti tetaragmenoi este — why are you disturbed? why have you been shaken? tarassō = to stir up, to agitate, to disturb; the perfect passive: in a settled state of agitation) — Jesus addresses the fear directly. "Why do thoughts arise in your hearts?" (dia ti dialogismoi anabainousin en tē kardia humōn — why do doubts/reasonings rise up in your hearts? dialogismos = internal debate, reasoning, doubt; anabainō = to go up, to rise) — the doubts are arising from within, not from the evidence. The hearts that were slow to believe (v.25) are now generating objections. Jesus will address these doubts empirically: by showing his hands and feet (v.39) and eating physical food (v.42-43), demonstrating the bodily, material reality of his resurrection against the "ghost" hypothesis.', NULL),
  (39, 'Behold my hands and my feet, that it is I myself: handle me, and see; for a spirit hath not flesh and bones, as ye see me have.', 'ἴδετε τὰς χεῖράς μου καὶ τοὺς πόδας μου, ὅτι ἐγώ εἰμι αὐτός· ψηλαφήσατέ με καὶ ἴδετε, ὅτι πνεῦμα σάρκα καὶ ὀστέα οὐκ ἔχει καθὼς ἐμὲ θεωρεῖτε ἔχοντα.', 'idete tas cheiras mou kai tous podas mou, hoti egō eimi autos; psēlaphēsate me kai idete, hoti pneuma sarka kai ostea ouk echei kathōs eme theōreite echonta.', '"Behold my hands and my feet" (idete tas cheiras mou kai tous podas mou — see my hands and my feet) — the hands and feet bear the crucifixion wounds (nail marks), providing continuity between the crucified Jesus and the risen Jesus: the same person who died now lives. "That it is I myself" (hoti egō eimi autos — that I am he myself; the emphatic triple identification: egō/I, eimi/am, autos/myself). "Handle me, and see" (psēlaphēsate me kai idete — touch me and see; psēlaphaō = to feel, to grope, to handle by touching; the word is used in Acts 17:27 and 1 John 1:1) — the invitation to physical touch is the definitive refutation of the ghost hypothesis. "A spirit hath not flesh and bones" (pneuma sarka kai ostea ouk echei — a spirit does not have flesh and bones) — Jesus defines the resurrection body against two errors: it is not a disembodied spirit (it has flesh and bones) and it is not merely a resuscitated corpse (it can appear and vanish, vv.31, 36).', NULL),
  (40, 'And when he had thus spoken, he shewed them his hands and his feet.', 'καὶ τοῦτο εἰπὼν ἔδειξεν αὐτοῖς τὰς χεῖρας καὶ τοὺς πόδας.', 'kai touto eipōn edeixen autois tas cheiras kai tous podas.', '"He shewed them his hands and his feet" (edeixen autois tas cheiras kai tous podas — he showed them the hands and the feet) — the display of crucifixion wounds is the empirical evidence. The risen body retains the marks of the cross; resurrection does not erase the Passion but transforms it. The wounds are now signs of victory, not defeat — evidence of identity and proof of conquest. In the theology of the resurrection, the cross is not left behind but glorified. The nail-marks become the credentials of the risen Christ, the proof that the crucified one and the risen one are the same person. Thomas will later put his hand into these wounds (John 20:27) and confess: "My Lord and my God."', NULL),
  (41, 'And while they yet believed not for joy, and wondered, he said unto them, Have ye here any meat?', 'ἔτι δὲ ἀπιστούντων αὐτῶν ἀπὸ τῆς χαρᾶς καὶ θαυμαζόντων, εἶπεν αὐτοῖς, Ἔχετέ τι βρώσιμον ἐνθάδε;', 'eti de apistountōn autōn apo tēs charas kai thaumazontōn, eipen autois, Echete ti brōsimon enthade?', '"While they yet believed not for joy" (eti apistountōn autōn apo tēs charas — still disbelieving from joy; the fascinating phrase apo tēs charas/from joy indicates that their disbelief is now the product of overwhelming happiness rather than grief) — a psychologically profound observation: the reality is too good to be believed. "Wondered" (thaumazontōn — marveling; the combination of joy-based disbelief and wonder is a uniquely human response to the unimaginable). "Have ye here any meat?" (Echete ti brōsimon enthade — do you have anything edible here? brōsimos = edible, fit to eat) — the request for food is the final proof of bodily resurrection: a ghost cannot eat. The ordinary domesticity of the request — asking for food in a room of astonished disciples — is characteristically Lucan: the supernatural is grounded in the natural.', NULL),
  (42, 'And they gave him a piece of a broiled fish, and of an honeycomb.', 'οἱ δὲ ἐπέδωκαν αὐτῷ ἰχθύος ὀπτοῦ μέρος·', 'hoi de epedōkan autō ichtuos optou meros;', '"They gave him a piece of a broiled fish" (epedōkan autō ichtuos optou meros — they gave him a portion of a broiled fish; ichthus = fish; optos = roasted, broiled; meros = part, portion) — the mention of "and of an honeycomb" (kai apo melissiou kēriou) is present in some manuscripts but absent from the earliest and best witnesses, likely a scribal addition. The broiled fish is a simple, common food — the kind of food available in a Jerusalem household on an ordinary evening. Jesus eats real food in a real body: the resurrection is material and physical, not merely spiritual or visionary. The fish also connects to Jesus'' ministry: he called fishermen (5:1-11), multiplied fish (9:16), and will eat fish again on the lakeshore (John 21:9-13).', NULL),
  (43, 'And he took it, and did eat before them.', 'καὶ λαβὼν ἐνώπιον αὐτῶν ἔφαγεν.', 'kai labōn enōpion autōn ephagen.', '"He took it, and did eat before them" (labōn enōpion autōn ephagen — having taken it, he ate in their presence; enōpion = before, in the sight of, in their full view) — the emphasis on "before them" (enōpion autōn) makes the eating a witnessed, public act, not a private or ambiguous event. Jesus eats so that the disciples can see him eat. The act of eating fulfills the proof that he is not a spirit (v.39): a ghost cannot consume physical food. Acts 10:41 will later cite this as foundational testimony: "who did eat and drink with him after he rose from the dead." The risen Christ shares table fellowship with his disciples — the pattern that began in his earthly ministry (5:29-30; 7:36; 14:1; 22:14-20) continues beyond the resurrection.', NULL),
  (44, 'And he said unto them, These are the words which I spake unto you, while I was yet with you, that all things must be fulfilled, which were written in the law of Moses, and in the prophets, and in the psalms, concerning me.', 'Εἶπεν δὲ πρὸς αὐτούς, Οὗτοι οἱ λόγοι μου οὓς ἐλάλησα πρὸς ὑμᾶς ἔτι ὢν σὺν ὑμῖν, ὅτι δεῖ πληρωθῆναι πάντα τὰ γεγραμμένα ἐν τῷ νόμῳ Μωϋσέως καὶ τοῖς προφήταις καὶ ψαλμοῖς περὶ ἐμοῦ.', 'Eipen de pros autous, Houtoi hoi logoi mou hous elalēsa pros humas eti ōn sun humin, hoti dei plērōthēnai panta ta gegrammena en tō nomō Mōuseōs kai tois prophētais kai psalmois peri emou.', '"These are the words which I spake unto you" (Houtoi hoi logoi mou — these are my words) — Jesus connects the post-resurrection teaching to his pre-crucifixion instruction. "While I was yet with you" (eti ōn sun humin — while I was still with you; the phrase implies a changed mode of presence: he was with them before; now he is with them differently). "That all things must be fulfilled" (dei plērōthēnai panta — it is necessary for all things to be fulfilled; dei again, divine necessity). "In the law of Moses, and in the prophets, and in the psalms" (en tō nomō Mōuseōs kai tois prophētais kai psalmois) — the three divisions of the Hebrew Bible: Torah (Law), Neviim (Prophets), and Ketuvim (Writings, represented by "Psalms," the largest book of the Ketuvim). "Concerning me" (peri emou — about me) — the entire Hebrew canon witnesses to Christ. This is the most comprehensive statement of OT Christology in the Gospels.', NULL),
  (45, 'Then opened he their understanding, that they might understand the scriptures,', 'τότε διήνοιξεν αὐτῶν τὸν νοῦν τοῦ συνιέναι τὰς γραφάς,', 'tote diēnoixen autōn ton noun tou sunienai tas graphas,', '"Opened he their understanding" (diēnoixen autōn ton noun — he opened their mind; dianoigō = to open thoroughly, the same word used for opening their eyes at Emmaus, v.31, and opening the Scriptures, v.32; nous = mind, intellect, understanding) "that they might understand the scriptures" (tou sunienai tas graphas — to understand the Scriptures; suniēmi = to bring together, to comprehend, to grasp the meaning by putting things together). The divine concealment of 9:45 ("this saying was hid from them") and 18:34 ("they understood none of these things") is now definitively reversed. What God hid during the ministry he now reveals after the resurrection. The "opening" is a divine act: understanding Scripture requires not merely better exegesis but a divinely opened mind. This verse is the hinge between the concealment of the passion and the comprehension of the resurrection.', NULL),
  (46, 'And said unto them, Thus it is written, and thus it behoved Christ to suffer, and to rise from the dead the third day:', 'καὶ εἶπεν αὐτοῖς ὅτι Οὕτως γέγραπται παθεῖν τὸν Χριστὸν καὶ ἀναστῆναι ἐκ νεκρῶν τῇ τρίτῃ ἡμέρᾳ,', 'kai eipen autois hoti Houtōs gegraptai pathein ton Christon kai anastēnai ek nekrōn tē tritē hēmera,', '"Thus it is written" (Houtōs gegraptai — thus it stands written; the perfect tense: written in the past with continuing authority) — the appeal to Scripture as the authoritative framework for understanding the cross and resurrection. "It behoved Christ to suffer" (pathein ton Christon — for the Christ to suffer; the dei/divine necessity is implied from v.44) — the suffering Messiah is not a contradiction of messianic prophecy but its fulfillment. "And to rise from the dead the third day" (anastēnai ek nekrōn tē tritē hēmera — and to rise from among the dead on the third day; the "third day" connects to Hosea 6:2, Jonah 1:17/Matt 12:40, and the pattern of resurrection after three days in Jewish thought) — suffering and resurrection are presented as a single divine program, not separate events. The cross without the resurrection would be tragedy; the resurrection without the cross would be cheap triumph. Together they constitute the gospel.', NULL),
  (47, 'And that repentance and remission of sins should be preached in his name among all nations, beginning at Jerusalem.', 'καὶ κηρυχθῆναι ἐπὶ τῷ ὀνόματι αὐτοῦ μετάνοιαν εἰς ἄφεσιν ἁμαρτιῶν εἰς πάντα τὰ ἔθνη, ἀρξάμενοι ἀπὸ Ἰερουσαλήμ.', 'kai kēruchthēnai epi tō onomati autou metanoian eis aphesin hamartiōn eis panta ta ethnē, arxamenoi apo Ierousalēm.', '"Repentance and remission of sins should be preached" (kēruchthēnai...metanoian eis aphesin hamartiōn — to be proclaimed...repentance for forgiveness of sins; kērussō = to herald, to proclaim publicly; metanoia = a change of mind, repentance, turning; aphesis = release, forgiveness, letting go; hamartia = sin, missing the mark) — the content of the apostolic proclamation is defined: repentance and forgiveness. "In his name" (epi tō onomati autou — in/upon his name) — the authority and basis of the proclamation. "Among all nations" (eis panta ta ethnē — to all the nations/peoples) — the universal scope: not Israel only but every nation. "Beginning at Jerusalem" (arxamenoi apo Ierousalēm — beginning from Jerusalem) — the geographic starting point, programmatic for Acts (Acts 1:8: "in Jerusalem, and in all Judaea, and in Samaria, and unto the uttermost part of the earth"). Jerusalem is both the city that killed the Messiah and the city from which the gospel radiates outward.', NULL),
  (48, 'And ye are witnesses of these things.', 'ὑμεῖς μάρτυρες τούτων.', 'humeis martures toutōn.', '"Ye are witnesses of these things" (humeis martures toutōn — you are witnesses of these things; martures = witnesses, the root of "martyr") — the disciples'' identity is defined: they are witnesses (martures). The word carries both forensic (legal testimony) and existential (personal testimony born of experience) weight. "Of these things" (toutōn — of these things: the suffering, resurrection, and the promise of repentance and forgiveness for all nations) — their witness is not to abstract truths but to experienced events: they saw the crucifixion, they encountered the risen Lord, they heard his teaching. Acts will develop the concept: "ye shall be witnesses unto me" (Acts 1:8). The apostolic witness is the foundation of the church''s proclamation across all subsequent generations.', NULL),
  (49, 'And, behold, I send the promise of my Father upon you: but tarry ye in the city of Jerusalem, until ye be endued with power from on high.', 'καὶ ἰδοὺ ἐγὼ ἀποστέλλω τὴν ἐπαγγελίαν τοῦ Πατρός μου ἐφ'' ὑμᾶς· ὑμεῖς δὲ καθίσατε ἐν τῇ πόλει ἕως οὗ ἐνδύσησθε ἐξ ὕψους δύναμιν.', 'kai idou egō apostellō tēn epangelian tou Patros mou eph'' humas; humeis de kathisate en tē polei heōs hou endusēsthe ex hupsous dunamin.', '"I send the promise of my Father upon you" (egō apostellō tēn epangelian tou Patros mou eph'' humas — I am sending the promise of my Father upon you; the present tense apostellō = I am sending, indicating the process is already initiated) — "the promise of my Father" (tēn epangelian tou Patros) = the Holy Spirit (cf. Joel 2:28-29; Acts 1:4-5; 2:33). Jesus, the one who was sent (apostellō), now sends the Spirit. "Tarry ye in the city of Jerusalem" (kathisate en tē polei — sit/remain in the city; kathizō = to sit, to settle, to stay; the command is to wait, not to act) — the mission cannot begin without the empowerment. "Endued with power from on high" (endusēsthe ex hupsous dunamin — you will be clothed with power from on high; enduō = to put on, to clothe oneself in; hupsous = from the height, from above; dunamis = power, ability, the root of "dynamite") — the Spirit is described as power-clothing, a garment of divine enablement. Pentecost (Acts 2) is the fulfillment.', NULL),
  (50, 'And he led them out as far as to Bethany, and he lifted up his hands, and blessed them.', 'Ἐξήγαγεν δὲ αὐτοὺς ἔξω ἕως πρὸς Βηθανίαν, καὶ ἐπάρας τὰς χεῖρας αὐτοῦ εὐλόγησεν αὐτούς.', 'Exēgagen de autous exō heōs pros Bēthanian, kai eparas tas cheiras autou eulogēsen autous.', '"He led them out as far as to Bethany" (Exēgagen autous exō heōs pros Bēthanian — he led them out as far as toward Bethany; Bethany is on the eastern slope of the Mount of Olives, approximately two miles from Jerusalem, cf. Acts 1:12; the home of Mary, Martha, and Lazarus, 10:38-42; John 11:1) — the Ascension location connects to Jesus'' nightly retreats to the Mount of Olives (21:37) and the Gethsemane agony (22:39). "He lifted up his hands, and blessed them" (eparas tas cheiras autou eulogēsen autous — having lifted his hands, he blessed them; the priestly gesture of blessing, cf. Lev 9:22 where Aaron "lifted up his hand toward the people, and blessed them") — Jesus departs in the posture of the high priest, pronouncing a benediction over his people. The risen Christ''s final earthly act is a blessing.', NULL),
  (51, 'And it came to pass, while he blessed them, he was parted from them, and carried up into heaven.', 'καὶ ἐγένετο ἐν τῷ εὐλογεῖν αὐτὸν αὐτοὺς διέστη ἀπ'' αὐτῶν καὶ ἀνεφέρετο εἰς τὸν οὐρανόν.', 'kai egeneto en tō eulogein auton autous diestē ap'' autōn kai anephereto eis ton ouranon.', '"While he blessed them" (en tō eulogein auton autous — while he was blessing them) — the blessing is ongoing, unfinished, as he ascends: the risen Christ departs mid-benediction, as if the blessing continues from heaven. "He was parted from them" (diestē ap'' autōn — he was separated from them, he stood apart; diistēmi = to set apart, to separate) — the physical separation that initiates the new mode of Christ''s presence through the Spirit. "Carried up into heaven" (anephereto eis ton ouranon — was being carried up into heaven; anapherō = to carry up; the imperfect passive suggests a gradual, visible ascent) — some early manuscripts omit "and carried up into heaven," but the majority tradition and Acts 1:9-11 support it. The Ascension is the completion of the resurrection: Christ''s exaltation to the right hand of God (22:69), his return to the Father (John 16:28), and the inauguration of his heavenly reign.', NULL),
  (52, 'And they worshipped him, and returned to Jerusalem with great joy:', 'καὶ αὐτοὶ προσκυνήσαντες αὐτὸν ὑπέστρεψαν εἰς Ἰερουσαλὴμ μετὰ χαρᾶς μεγάλης,', 'kai autoi proskunēsantes auton hupestrepsan eis Ierousalēm meta charas megalēs,', '"They worshipped him" (proskunēsantes auton — having worshipped him; proskuneō = to bow down before, to worship, to do obeisance; from pros/toward + kuneō/to kiss; the full gesture of divine worship) — this is the first time in Luke that the disciples worship Jesus with the explicit verb of divine worship (proskuneō). The resurrection and ascension have clarified his identity: he is worthy of worship. "Returned to Jerusalem with great joy" (hupestrepsan eis Ierousalēm meta charas megalēs — they returned to Jerusalem with great joy; chara = joy, the characteristic Lucan emotion, cf. 1:14; 2:10; 10:17; 15:7, 10) — the contrast with the Emmaus journey is total: two disciples walked away from Jerusalem in despair (v.17); the community now returns to Jerusalem in worship and joy. The ascension does not produce grief at Christ''s departure but joy at his glorification.', NULL),
  (53, 'And were continually in the temple, praising and blessing God. Amen.', 'καὶ ἦσαν διὰ παντὸς ἐν τῷ ἱερῷ εὐλογοῦντες τὸν Θεόν.', 'kai ēsan dia pantos en tō hierō eulogountes ton Theon.', '"Continually in the temple" (dia pantos en tō hierō — through all time in the Temple; the periphrastic imperfect ēsan...eulogountes = they were continually blessing) — the disciples return to the Temple, the same Temple where the Gospel opened with Zechariah''s service (1:8-10) and where the infant Jesus was presented (2:22-38). The Gospel ends where it began: in the Temple, in worship. "Praising and blessing God" (eulogountes ton Theon — blessing God; some manuscripts add "praising and" [ainountes kai]) — the final word of Luke''s Gospel is doxology. The community that began in fear (v.37), moved through doubt (v.41), received understanding (v.45), and was commissioned as witnesses (v.48) now rests in worship. "Amen" — the concluding affirmation, present in some manuscripts, sealing the Gospel with the community''s response of faith. The story does not end but continues in Acts, where the same Temple becomes the venue for Pentecost and the first apostolic preaching.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 24;

-- LUKE CHAPTER 24 — BACKFILL (word_studies + cross_references)

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ὄρθρου βαθέως', 'orthrou batheōs', 'G3722', 'Deep dawn — lit. "dawn in its depth," the predawn twilight. Luke''s time-marker pointedly emphasizes how early: the first act of the new creation week occurs before full sunrise — day of resurrection dawns on a world still in dark.', 1),
  (1, 'ἀρώματα', 'arōmata', 'G759', 'Aromatics/spices — the burial preparations (prepared on Friday, 23:56) the women now bring for full anointing that the rushed Friday burial could not accomplish. Their devotion is unwavering; they come to care for a body they believe dead.', 2),
  (2, 'ἀποκεκυλισμένον', 'apokekulismenon', 'G617', 'Rolled away — perfect passive participle: "having been rolled away and still in that state." The stone (typically a disk-shaped rolling stone in a track, two tons or more) did not roll itself; the passive voice implies divine agency.', 1),
  (4, 'ἀπορεῖσθαι', 'aporeisthai', 'G639', 'Perplexed — from aporeō (to be without a way/path, to be at a loss). The women face a mystery without an obvious interpretive path; the empty tomb is surprising data that initially puzzles rather than explains.', 1),
  (4, 'ἐσθήτεσιν ἀστραπτούσαις', 'esthēsesin astraptousais', 'G796', 'Flashing/dazzling clothing — astraptō = to flash like lightning. Angelic visitation attested by luminous vesture (cf. Dan 10:6; Matt 28:3). The two men echo Moses and Elijah on the mount of transfiguration (9:30) — the same witnesses to resurrection-glory.', 1),
  (5, 'ζῶντα μετὰ τῶν νεκρῶν', 'zōnta meta tōn nekrōn', 'G2198', 'The living among the dead — the rebuke is paradigmatic: seeking Jesus in the tomb confuses categories. Resurrection reclassifies Jesus fundamentally; he is no longer subject to death''s geography.', 1),
  (6, 'ἠγέρθη', 'ēgerthē', 'G1453', 'He is risen — aorist passive of egeirō (to raise/wake). Passive voice: "he was raised" — the Father is the agent of resurrection (cf. Acts 2:24; 3:15; Rom 10:9). The divine vindication of the Son answers the verdict of the Sanhedrin.', 1),
  (11, 'λῆρος', 'lēros', 'G3026', 'Idle tale/nonsense — lit. "empty talk," delirium, the raving of someone with fever. The apostles dismissed the women''s testimony as hysterical babble. Luke preserves the disciples'' initial unbelief, underscoring that resurrection faith is not wishful projection.', 1),
  (13, 'σταδίους ἑξήκοντα', 'stadious hexēkonta', 'G4712', 'Sixty stadia — ~7 miles (11 km). One stadion = ~185 m (the length of the Olympic footrace stadium). Emmaus'' exact identification is debated; the distance permits a return journey to Jerusalem the same day (v.33).', 1),
  (16, 'ἐκρατοῦντο', 'ekratounto', 'G2902', 'Were restrained/held — lit. "were being held fast." The imperfect passive: their eyes were kept from recognizing. Divine agency both conceals and later opens (v.31) — recognition is a gift that arrives in Jesus''s chosen moment.', 1),
  (21, 'ἠλπίζομεν', 'ēlpizomen', 'G1679', 'We were hoping — imperfect tense: hope once sustained but now broken. The past-tense of hope captures the disciples'' desolation: "we were hoping" — the crucifixion shattered their eschatology.', 1),
  (21, 'λυτροῦσθαι', 'lutrousthai', 'G3084', 'To redeem — lutroō = to ransom, to buy back. The disciples awaited a political-national redemption (cf. 1:68; 2:38); the cross has apparently falsified the expectation. Jesus''s teaching will reveal a deeper redemption accomplished precisely through the cross.', 2),
  (25, 'ἀνόητοι', 'anoētoi', 'G453', 'Foolish/unperceptive — lit. "without mind" (a- + noēma); not intellectually stupid but failing to perceive what is clearly there. The rebuke applies equally to every reader who reads the prophets without seeing Christ.', 1),
  (25, 'βραδεῖς τῇ καρδίᾳ', 'bradeis tē kardia', 'G1021', 'Slow of heart — bradus = slow, dull. Not slowness of intellect but reluctance of heart to believe. The heart, not the head, is the obstacle; the problem is willingness to trust, not capacity to comprehend.', 2),
  (26, 'ἔδει', 'edei', 'G1163', 'Must/was necessary — the impersonal form of deō (to be necessary) carrying theological freight throughout Luke (2:49; 9:22; 17:25; 22:37; 24:7, 44). The sufferings were not tragic accident but divine necessity — the predetermined Scripture-shaped way of messianic glory.', 1),
  (27, 'Μωϋσέως καὶ ἀπὸ πάντων τῶν προφητῶν', 'Mōuseōs kai apo pantōn tōn prophētōn', 'G3475', 'Moses and all the prophets — the two-part canon (the rest elaborated at v.44 as Moses-Prophets-Psalms) serving as foundation for christological interpretation. The whole OT is now read through the prism of the suffering-and-glorified Christ.', 1),
  (27, 'διερμήνευσεν', 'diermēneusen', 'G1329', 'Expounded/interpreted thoroughly — from dia/through + hermēneuō/interpret. The cognate of "hermeneutics." Jesus provides the definitive hermeneutical key to the Hebrew Scriptures; every subsequent Christian reading of the OT descends from this Emmaus tutorial.', 2),
  (30, 'λαβὼν...εὐλόγησεν...κλάσας...ἐπεδίδου', 'labōn...eulogēsen...klasas...epedidou', 'G2806', 'Took...blessed...broke...gave — the four-fold sequence identical to the feeding of the 5000 (9:16) and the Last Supper (22:19). The table gesture is Jesus''s signature; in it recognition finally breaks through.', 1),
  (31, 'διηνοίχθησαν', 'diēnoichthēsan', 'G1272', 'Were opened (thoroughly) — dia/through + anoigō/open. The same verb will recur for the opened Scriptures (v.32) and the opened understanding (v.45). Recognition, understanding, and Scripture-opening are one divine work.', 1),
  (31, 'ἄφαντος', 'aphantos', 'G855', 'Vanishing/invisible — from a- + phainō (to appear) = not appearing. Jesus does not walk out; he simply becomes invisible. The resurrection body is no longer bound by ordinary spatial constraints.', 2),
  (32, 'ἡ καρδία ἡμῶν καιομένη', 'hē kardia hēmōn kaiomenē', 'G2545', 'Our heart burning — kaiō = to ignite, to set on fire. The heart''s retrospective recognition: the word-ministry already ignited them, though their eyes could not yet see. A paradigm for all Scripture-exposition that kindles the heart.', 1),
  (34, 'Ὤφθη Σίμωνι', 'Ōphthē Simōni', 'G3700', 'He has appeared to Simon — Peter''s individual resurrection appearance (corroborated in 1 Cor 15:5). Luke mentions but does not narrate the meeting, honoring it as the private restoration of the shepherd-to-be. The note vindicates Peter''s post-denial future.', 1),
  (37, 'πτοηθέντες...ἔμφοβοι', 'ptoēthentes...emphoboi', 'G1790', 'Terrified and frightened — ptoeō = to be struck with terror; emphobos = in fear. Their fear at an apparently bodiless appearance is the same fear the women had at the empty tomb (v.5). Resurrection upsets ordinary categories; terror is the natural first response.', 1),
  (37, 'πνεῦμα', 'pneuma', 'G4151', 'A spirit/ghost — the disciples assumed a disembodied apparition rather than bodily resurrection. Jesus''s physical demonstrations (vv.39-43) are directed precisely against this spiritualizing error: resurrection is bodily, not merely spectral.', 2),
  (39, 'σάρκα καὶ ὀστέα', 'sarka kai ostea', 'G4561', 'Flesh and bones — not "flesh and blood" (which denotes mortal humanity, 1 Cor 15:50) but "flesh and bones," a concrete demonstration of bodily materiality. The risen Lord is not merely a ghost; he has a body — glorified but real.', 1),
  (41, 'ἀπιστούντων...ἀπὸ τῆς χαρᾶς', 'apistountōn...apo tēs charas', 'G570', 'Disbelieving for joy — apisteō = to disbelieve. A beautifully human note: the resurrection is too good to be immediately assimilated. The heart that was dead to hope cannot instantly open to grace too great.', 1),
  (42, 'ἰχθύος ὀπτοῦ', 'ichthuos optou', 'G3702', 'Broiled fish — optos = roasted, broiled. Jesus eats real food in visible continuity with his pre-Passion meals. The fish parallels the breakfast by the sea (John 21:9-13); table-fellowship vindicates the reality of the bodily resurrection.', 1),
  (44, 'νόμῳ Μωϋσέως καὶ προφήταις καὶ ψαλμοῖς', 'nomō Mōuseōs kai prophētais kai psalmois', 'G3551', 'Law of Moses and prophets and psalms — the three-fold Hebrew canon (Torah, Nevi''im, Ketuvim), with Psalms representing the Writings as its largest book. Christ is claimed by the whole Hebrew Bible, not just the prophets.', 1),
  (45, 'διήνοιξεν αὐτῶν τὸν νοῦν', 'diēnoixen autōn ton noun', 'G3563', 'Opened their understanding — lit. "opened their mind thoroughly." The mind (nous) parallels the heart (v.32) and the eyes (v.31): each must be opened by Christ. Scriptural understanding is a work of the risen Lord, not a natural human achievement.', 1),
  (46, 'παθεῖν τὸν Χριστὸν καὶ ἀναστῆναι', 'pathein ton Christon kai anastēnai', 'G3958', 'For the Christ to suffer and to rise — suffering-then-resurrection as the scriptural necessity. The pattern matches Isa 53 (suffering servant) + Hos 6:2/Ps 16:10 (raised on the third day). Passion + resurrection are a single indivisible shape.', 1),
  (47, 'μετάνοιαν εἰς ἄφεσιν ἁμαρτιῶν', 'metanoian eis aphesin hamartiōn', 'G3341', 'Repentance unto forgiveness of sins — metanoia = change of mind/return; aphesis = release/remission. The content of apostolic proclamation: the saving shift of human orientation, with remission as its divine result.', 1),
  (47, 'εἰς πάντα τὰ ἔθνη', 'eis panta ta ethnē', 'G1484', 'Unto all the nations — the Gentile horizon of the gospel is the Lucan programmatic agenda (cf. 2:32; Acts 1:8; 13:46-47). Mission to the nations is not a secondary afterthought but the very substance of the scriptural plan.', 2),
  (48, 'μάρτυρες', 'martures', 'G3144', 'Witnesses — the forensic-existential term that will define the apostolic identity (cf. Acts 1:8; 2:32; 3:15; 5:32). The eyewitness root of later Christian "martyrdom" lies here: the ones who testify become, finally, the ones who suffer for testimony.', 1),
  (49, 'ἐπαγγελίαν τοῦ Πατρός', 'epangelian tou Patros', 'G1860', 'Promise of the Father — the Holy Spirit (cf. Acts 1:4; 2:33; John 14:16-17, 26). The OT promise of the Spirit poured out (Joel 2:28-29; Ezek 36:26-27; Isa 44:3) reaches its fulfillment at Pentecost.', 1),
  (49, 'ἐνδύσησθε ἐξ ὕψους δύναμιν', 'endusēsthe ex hupsous dunamin', 'G1746', 'Ye be clothed with power from on high — enduō = to clothe; the Spirit is garment-like power, an investiture for mission. "From on high" echoes Isa 32:15 (LXX) — the Spirit poured "from on high" brings eschatological fruitfulness.', 2),
  (50, 'ἐπάρας τὰς χεῖρας', 'eparas tas cheiras', 'G1869', 'Having lifted his hands — the priestly blessing gesture (Lev 9:22; Num 6:23-27). The risen Christ departs as the true high priest, pronouncing the Aaronic benediction in person upon his people.', 1),
  (51, 'ἀνεφέρετο εἰς τὸν οὐρανόν', 'anephereto eis ton ouranon', 'G399', 'Was carried up into heaven — anapherō = to lift/carry upward; imperfect passive: he was being carried up (gradual, visible ascent). The Ascension completes the resurrection: enthronement at God''s right hand (Ps 110:1; 22:69; Acts 1:9; 2:33-36).', 1),
  (52, 'προσκυνήσαντες', 'proskunēsantes', 'G4352', 'Worshipped — proskuneō = to bow down before, to offer divine worship. For the first time in Luke, the disciples render proskunēsis to Jesus without qualification — a decisive christological marker: the risen and ascended Lord is object of worship.', 1),
  (53, 'εὐλογοῦντες τὸν Θεόν', 'eulogountes ton Theon', 'G2127', 'Blessing God — the participial imperfect closes the Gospel: they were continually blessing God. Luke''s Gospel ends in the Temple with doxology, exactly where it began (1:8-10; Zacharias). The circle of divine blessing is closed, awaiting the outpouring that will open Acts.', 1)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Luke' AND c.chapter_number = 24 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

